from typing import List
import heapq

def solve(m: int, n: int, waitCost: List[List[int]]) -> int:
    # Directions: right and down
    directions = [(0, 1), (1, 0)]

    # Priority queue: (total_cost, time, row, col)
    pq = [(0, 0, 0, 0)]
    # Visited matrix to keep track of the minimum cost to reach each cell at a certain time
    visited = [[float('inf')] * n for _ in range(m)]
    visited[0][0] = 0  # Initial cost at (0, 0) is 0 (no cost yet)

    # Cost to enter a cell (i, j)
    def enter_cost(i, j):
        return (i + 1) * (j + 1)

    # Cost to wait at a cell (i, j)
    def wait_cost(i, j):
        return waitCost[i][j]

    while pq:
        total_cost, time, i, j = heapq.heappop(pq)

        # If we reach the destination
        if i == m - 1 and j == n - 1:
            return total_cost

        # If current total cost is higher than the recorded minimum, skip
        if total_cost > visited[i][j]:
            continue

        # If current time is odd (1, 3, 5, ...), we can move right or down
        if time % 2 == 1:
            for dx, dy in directions:
                ni, nj = i + dx, j + dy
                if 0 <= ni < m and 0 <= nj < n:
                    new_time = time + 1
                    new_cost = total_cost + enter_cost(ni, nj)
                    if new_cost < visited[ni][nj]:
                        visited[ni][nj] = new_cost
                        heapq.heappush(pq, (new_cost, new_time, ni, nj))
        else:
            # If current time is even, we must wait
            new_time = time + 1
            new_cost = total_cost + wait_cost(i, j)
            if new_cost < visited[i][j]:
                visited[i][j] = new_cost
                heapq.heappush(pq, (new_cost, new_time, i, j))

    return -1  # If no path found (should not happen for valid inputs)
